const trigger = $('Telegram Trigger').first().json;
const fromId = String(trigger?.message?.from?.id ?? trigger?.message?.chat?.id ?? '');
const text = String(trigger?.message?.text ?? '').trim();
const allowed = $input.all().map(i => String(i.json.chat_id ?? '').trim()).filter(Boolean);
const hasBot = !!fromId && allowed.includes(fromId);
// нет доступа к AI или это /start (интро отдаёт отдельная ветка) → не сюда
if (!hasBot || /^\/start\b/.test(text)) return [];
return [{ json: trigger }];

// Build <context> block for the LLM and pull short-term memory.
const merge = $('Merge Text').first().json;
const chat_id = String(merge.chat_id);
const user_text = merge.user_text;

const pad = (n) => String(n).padStart(2, '0');
const now = new Date();
const today = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;

// --- Profile -------------------------------------------------------------
const profileRows = $('Read Profile').all().map(i => i.json);
const profileRow = profileRows.find(r => String(r.chat_id) === chat_id) || null;
const interval = Number(profileRow?.training_days_interval) || 1;

// --- Today's food sum ----------------------------------------------------
const foodRows = $('Read Food Log').all().map(i => i.json);
const todayFood = foodRows.filter(r => String(r.date) === today);
const todaySum = todayFood.reduce((acc, r) => ({
  kcal:    acc.kcal    + (Number(r.kcal)    || 0),
  protein: acc.protein + (Number(r.protein) || 0),
  fat:     acc.fat     + (Number(r.fat)     || 0),
  carbs:   acc.carbs   + (Number(r.carbs)   || 0),
}), { kcal: 0, protein: 0, fat: 0, carbs: 0 });
// Округление — иначе плавучка даёт 655.6999999999998
todaySum.kcal    = Math.round(todaySum.kcal);
todaySum.protein = Math.round(todaySum.protein * 10) / 10;
todaySum.fat     = Math.round(todaySum.fat * 10) / 10;
todaySum.carbs   = Math.round(todaySum.carbs * 10) / 10;

// --- Last workout --------------------------------------------------------
const workoutRows = $('Read Workout Log').all().map(i => i.json);
const sortedW = workoutRows
  .filter(r => r.date)
  .sort((a, b) => String(a.date).localeCompare(String(b.date)));
const lastWorkout = sortedW[sortedW.length - 1] || null;
// Тренировка, подтверждённая ИМЕННО сегодня (чтобы не показывать «отдых» после лога).
const trainedTodayLog = workoutRows.find(r => String(r.date) === today) || null;

// --- Workout blocks state (вкл/выкл блоков) ----------------------------
const blocksStateRows = $('Read Workout Blocks').all().map(i => i.json);
const blocksState = {};
for (const r of blocksStateRows) {
  const n = Number(r.block_num);
  if (!n) continue;
  blocksState[n] = {
    label: r.label || `№${n}`,
    active: String(r.active).toUpperCase() === 'TRUE',
  };
}
// Если лист пустой — считаем все 4 блока активными с дефолтными лейблами.
if (!Object.keys(blocksState).length) {
  for (const n of [1,2,3,4]) blocksState[n] = { label: `№${n}`, active: true };
}
const activeNums = Object.keys(blocksState).map(Number)
  .filter(n => blocksState[n].active).sort((a,b) => a-b);
const inactiveNums = Object.keys(blocksState).map(Number)
  .filter(n => !blocksState[n].active).sort((a,b) => a-b);
function nextActiveAfter(lastN, active) {
  if (!active.length) return null;
  const after = active.find(n => n > lastN);
  return after != null ? after : active[0];
}

function parseWorkoutNumber(plan) {
  if (!plan) return null;
  const m = String(plan).match(/№?\s*([1-4])/);
  if (m) return Number(m[1]);
  const s = String(plan).toLowerCase();
  if (s.includes('грудь') && s.includes('бицепс')) return 1;
  if (s.includes('плечи') && s.includes('грудь'))  return 2;
  if (s.includes('спина') && s.includes('трицепс'))return 3;
  if (s.includes('ноги')) return 4;
  return null;
}

let expected_today;
if (!activeNums.length) {
  expected_today = { type: 'rest', days_until_next: null, reason: 'no_active_blocks' };
} else if (!lastWorkout) {
  const n = activeNums[0];
  expected_today = { type: 'workout', number: n, label: blocksState[n].label };
} else {
  const lastDate = new Date(String(lastWorkout.date));
  const todayD   = new Date(today);
  const daysSince = Math.floor((todayD - lastDate) / (1000*60*60*24));
  if (daysSince < interval) {
    expected_today = { type: 'rest', days_until_next: interval - daysSince };
  } else {
    const lastN = parseWorkoutNumber(lastWorkout.day_plan) || 0;
    const nextN = nextActiveAfter(lastN, activeNums);
    expected_today = { type: 'workout', number: nextN, label: blocksState[nextN].label };
  }
}

// --- Workouts catalog (читается из листа workouts_flat) -----------------
const wkRows = $('Read Workouts Catalog').all().map(i => i.json);
const blocks = { 1: [], 2: [], 3: [], 4: [] };
for (const r of wkRows) {
  const n = Number(r.block_num);
  if (!n || !blocks[n]) continue;
  if (!r.exercise) continue;
  blocks[n].push({
    group:    r.group    || '',
    exercise: r.exercise || '',
    sets:     r.sets     != null ? String(r.sets)   : '',
    reps:     r.reps     != null ? String(r.reps)   : '',
    weight:   r.weight   != null ? String(r.weight) : '',
    note:     r.note     || '',
  });
}
// BLOCK_LABELS теперь приходят из листа workout_blocks (см. blocksState выше).

// --- Short-term memory (per chat_id, persists in workflow staticData) ----
const sd = $getWorkflowStaticData('global');
sd.chats = sd.chats || {};
sd.chats[chat_id] = sd.chats[chat_id] || { recent: [], last_intent: null, last_intent_date: null };
const mem = sd.chats[chat_id];
// Если последний intent был не сегодня — сбрасываем, не тащим вчерашнее в контекст.
if (mem.last_intent_date && mem.last_intent_date !== today) {
  mem.last_intent = null;
  mem.last_intent_date = null;
}
const recentDialog = (mem.recent || []).slice(-6);

// --- Compose <context> ---------------------------------------------------
const lines = [];
lines.push('<context>');
if (profileRow) {
  lines.push(`Профиль: рост=${profileRow.height_cm}см, вес=${profileRow.weight_kg}кг, возраст=${profileRow.age}, пол=${profileRow.sex}, цель=${profileRow.goal || 'не задана'}.`);
  const bmr = Number(profileRow.bmr) || 1600;
  const baseline = Number(profileRow.daily_baseline_kcal) || 280;
  const goal = String(profileRow.goal || 'maintain').toLowerCase();
  const goalMult = ({ lose: 0.8, maintain: 1.0, gain: 1.15 })[goal] || 1.0;

  // --- Реальный расход за сегодня (динамически) ----------------------
  // Ходьба за сегодня:
  const walkRows = $('Read Walking Log').all().map(i => i.json).filter(r => String(r.date) === today);
  const walkKcalToday = walkRows.reduce((s, r) => s + (Number(r.kcal_burned) || 0), 0);
  const walkMinToday  = walkRows.reduce((s, r) => s + (Number(r.duration_min) || 0), 0);

  // Тренировки за сегодня:
  const todayWorkouts = workoutRows.filter(r => String(r.date) === today);
  const workoutKcalActual = todayWorkouts.reduce((s, r) => s + (Number(r.kcal_burned) || 0), 0);

  // Тренировка попадает в бюджет ТОЛЬКО после ПОДТВЕРЖДЕНИЯ (есть строка workout_log
  // за сегодня) и строго по ФАКТУ kcal_burned (он уже посчитан по ВЫПОЛНЕННЫМ
  // упражнениям — в Mini App done_workout_stats / при log_workout). Плановый расход
  // заранее в бюджет НЕ добавляем — так же, как в приложении (compute_dashboard).
  const workoutKcalToday = workoutKcalActual;

  const tdeeToday = bmr + baseline + walkKcalToday + workoutKcalToday;
  const targetKcalToday = Math.round(tdeeToday * goalMult);

  // Минимум — не уходить ниже BMR × 1.1; максимум — не выше базового × 1.4
  const targetFloor = Math.round(bmr * 1.1);
  const targetCap   = Math.round((bmr + baseline) * goalMult * 1.4);
  const targetKcalTodayClamped = Math.max(targetFloor, Math.min(targetCap, targetKcalToday));

  lines.push(`📊 Расчёт расхода на сегодня:`);
  lines.push(`- BMR: ${bmr} ккал`);
  lines.push(`- Повседневная активность (фон): ${baseline} ккал`);
  if (walkRows.length) {
    lines.push(`- Ходьба сегодня всего: ${walkMinToday} мин, ${walkKcalToday} ккал. Сессии:`);
    for (const r of walkRows) {
      const act = r.activity || 'walking';
      const sp  = r.speed_kmh ? `${r.speed_kmh} км/ч` : '?';
      const dist = r.distance_km ? `${r.distance_km}км ` : '';
      lines.push(`  · ${r.time || ''} ${act}: ${r.duration_min}мин ${dist}@ ${sp} → ${r.kcal_burned} ккал`);
    }
  } else {
    lines.push(`- Ходьба сегодня: ещё не залогирована`);
  }
  if (todayWorkouts.length) {
    lines.push(`- Тренировка сегодня (факт, подтверждена): ${workoutKcalToday} ккал — учтено в бюджете.`);
  } else if (expected_today.type === 'workout') {
    lines.push(`- Тренировка сегодня по плану (${expected_today.label}): ещё НЕ подтверждена → в бюджет НЕ учтена. Учтётся после подтверждения (по фактически выполненным упражнениям).`);
  } else {
    lines.push(`- Тренировка сегодня: ещё не было/не залогирована`);
  }
  lines.push(`- Итого расход: ${tdeeToday} ккал`);
  if (targetKcalTodayClamped !== targetKcalToday) {
    if (targetKcalTodayClamped < targetKcalToday) {
      lines.push(`Сырой расчёт цели: ${targetKcalToday} ккал. ⚠️ Сработал ПОТОЛОК (cap = базовая цель × 1.4 = ${targetCap} ккал). Это страховка — если за день много активности, бюджет всё равно не растёт выше ${targetCap}, чтобы не съесть лишнего «под расход».`);
      lines.push(`Цель на сегодня (с учётом cap): ${targetKcalTodayClamped} ккал.`);
    } else {
      lines.push(`Сырой расчёт цели: ${targetKcalToday} ккал. ⚠️ Сработал ПОЛ (floor = BMR × 1.1 = ${targetFloor} ккал). Это защита — нельзя уходить ниже, иначе слишком жёсткий дефицит.`);
      lines.push(`Цель на сегодня (с учётом floor): ${targetKcalTodayClamped} ккал.`);
    }
  } else {
    lines.push(`Цель (${goal} × ${goalMult}): ${targetKcalTodayClamped} ккал.`);
  }
  lines.push(`Белок: ${profileRow.target_protein_g}г, жиры: ${profileRow.target_fat_g}г, углеводы: ${profileRow.target_carbs_g}г.`);
  lines.push(`Интервал тренировок: ${interval} дн. Тип дня по циклу: ${trainedTodayLog ? 'тренировка ВЫПОЛНЕНА сегодня (' + trainedTodayLog.day_plan + ')' : (expected_today.type === 'workout' ? 'тренировка №' + expected_today.number : 'отдых')}.`);
  profileRow.__target_kcal_today = targetKcalTodayClamped;
} else {
  lines.push('Профиль НЕ заполнен. Если пользователь даёт антропометрию (рост/вес/возраст/пол/активность/цель) — используй action=set_profile. Если он сразу называет ккал-цель — action=set_goals.');
}
lines.push(`Сегодня (${today}) съедено: ${todaySum.kcal} ккал, Б=${todaySum.protein}г, Ж=${todaySum.fat}г, У=${todaySum.carbs}г.`);
if (todayFood.length) {
  lines.push('Записи food_log за сегодня (используй для daily_summary разбивкой):');
  for (const r of todayFood) {
    const t = r.time ? `${r.time} ` : '';
    const desc = r.description || '(без описания)';
    const kcal = r.kcal != null ? r.kcal : '?';
    const p = r.protein != null ? r.protein : '?';
    const f = r.fat != null ? r.fat : '?';
    const c = r.carbs != null ? r.carbs : '?';
    lines.push(`- ${t}${desc} — ${kcal} ккал (Б${p}/Ж${f}/У${c})`);
  }
}
if (profileRow?.target_kcal) {
  const targetToday = profileRow.__target_kcal_today || Number(profileRow.target_kcal);
  const left = Math.round(targetToday - todaySum.kcal);
  lines.push(`Остаток до цели на сегодня: ${left} ккал (${todaySum.kcal} съедено из ${targetToday}).`);
  // Подаём предыдущий остаток для расчёта движения бюджета.
  const prevRem = mem.last_remaining_kcal;
  if (prevRem != null && prevRem !== left) {
    const delta = Math.round(left - prevRem);
    const sign = delta >= 0 ? '+' : '';
    lines.push(`Прошлый остаток (до этого сообщения): ${prevRem} ккал. Движение: ${sign}${delta} ккал. ОБЯЗАТЕЛЬНО в reply покажи юзеру: «было ${prevRem} → стало ${left} ккал (${sign}${delta} за <причина>)».`);
  }
  // Сохраним текущий остаток для следующего хода
  mem.last_remaining_kcal = left;
}
if (profileRow?.target_protein_g) {
  const targetP = Number(profileRow.target_protein_g);
  const leftP = Math.round((targetP - todaySum.protein) * 10) / 10;
  lines.push(`Белок: ${todaySum.protein}г съедено из ${targetP}г. Осталось добрать: ${leftP}г.`);
}
if (profileRow?.target_fat_g) {
  const targetF = Number(profileRow.target_fat_g);
  lines.push(`Жиры: ${todaySum.fat}г из ${targetF}г.`);
}
if (profileRow?.target_carbs_g) {
  const targetC = Number(profileRow.target_carbs_g);
  lines.push(`Углеводы: ${todaySum.carbs}г из ${targetC}г.`);
}
if (lastWorkout) {
  lines.push(`Последняя тренировка: ${lastWorkout.date} — ${lastWorkout.day_plan}.`);
} else {
  lines.push('Тренировок ещё не было.');
}

// ════════════════ ПАТТЕРНЫ ПОСЛЕДНИХ 7 ДНЕЙ ════════════════
const last7Patterns = (() => {
  const out = [];
  const today0 = new Date(today + 'T00:00:00');

  // Прошлые 7 дней (исключая сегодня), по дате
  const days = [];
  for (let i = 1; i <= 7; i++) {
    const d = new Date(today0); d.setDate(d.getDate() - i);
    const ds = `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
    days.push(ds);
  }

  const targetK = Number(profileRow?.target_kcal) || 0;
  const targetP = Number(profileRow?.target_protein_g) || 0;

  // Дневные суммы food
  const perDay = {};
  for (const ds of days) perDay[ds] = { kcal: 0, protein: 0, items: 0, junk: 0, descs: [] };
  const JUNK = ['батончик','пицц','фастфуд','бургер','чипс','газировк','конфет','шоколад','мороженое','пончик','круассан','сухарик','шаурм','картош','кола','пепси'];
  for (const r of foodRows) {
    const ds = String(r.date);
    if (!(ds in perDay)) continue;
    perDay[ds].kcal += Number(r.kcal) || 0;
    perDay[ds].protein += Number(r.protein) || 0;
    perDay[ds].items += 1;
    const desc = String(r.description || '').toLowerCase();
    perDay[ds].descs.push(desc);
    if (JUNK.some(k => desc.includes(k))) perDay[ds].junk += 1;
  }

  // Стрики
  let overBudgetStreak = 0;
  let lowProteinStreak = 0;
  let zeroLogStreak = 0;
  for (const ds of days) {
    const d = perDay[ds];
    if (d.items === 0) zeroLogStreak += 1;
    else break; // streak от вчера назад
  }
  for (const ds of days) {
    const d = perDay[ds];
    if (targetK && d.kcal > targetK + 200) overBudgetStreak += 1; else break;
  }
  for (const ds of days) {
    const d = perDay[ds];
    if (targetP && d.protein < targetP * 0.7 && d.items > 0) lowProteinStreak += 1; else break;
  }

  // Общая сводка за 7 дней
  let weekKcal = 0, weekProtein = 0, weekJunk = 0, daysWithLog = 0;
  for (const ds of days) {
    const d = perDay[ds];
    if (d.items > 0) daysWithLog += 1;
    weekKcal += d.kcal; weekProtein += d.protein; weekJunk += d.junk;
  }

  const walkRows7 = $('Read Walking Log').all().map(i => i.json).filter(r => days.includes(String(r.date)));

  // Пропущенные плановые тренировки.
  // Окно ВКЛЮЧАЕТ сегодня: тренировка сегодня — НЕ пропуск.
  const wkWindow = new Set([today, ...days]);
  const workoutDaysInWin = new Set(
    workoutRows.map(r => String(r.date)).filter(d => wkWindow.has(d))
  );
  let actualWorkouts = workoutDaysInWin.size;
  // expected считаем от ПЕРВОЙ тренировки в окне по интервалу (а не плоско 7/interval),
  // чтобы старая дыра ДО окна не отравляла счёт. Сегодняшний слот пропуском не считаем —
  // день ещё не закрыт.
  let expectedWorkouts = 0;
  let missedWorkouts = 0;
  if (actualWorkouts >= 1) {
    const anchor = [...workoutDaysInWin].sort()[0];
    const daysDiff = Math.round((new Date(today + 'T00:00:00') - new Date(anchor + 'T00:00:00')) / 86400000);
    expectedWorkouts = Math.ceil(daysDiff / interval);
    missedWorkouts = Math.max(0, expectedWorkouts - actualWorkouts);
  }

  if (zeroLogStreak >= 2) out.push(`📉 ${zeroLogStreak} дн подряд НИЧЕГО не залогировано в food_log.`);
  if (overBudgetStreak >= 2) out.push(`🍕 ${overBudgetStreak} дн подряд превышен бюджет ккал на 200+.`);
  if (lowProteinStreak >= 2) out.push(`🥩 ${lowProteinStreak} дн подряд белок ниже 70% от цели.`);
  if (weekJunk >= 5) out.push(`⚠️ За неделю ${weekJunk} раз ели «мусорные» продукты (батончики/фастфуд/чипсы/сладкое).`);
  if (missedWorkouts >= 2) out.push(`💤 За 7 дней пропущено ~${missedWorkouts} плановых тренировок (сделано ${actualWorkouts} из ожидаемых ${expectedWorkouts}).`);
  if (daysWithLog === 0) out.push(`⚠️ За 7 дней ни одной записи еды. Юзер не пишет в бот.`);

  // Тренировка совсем давно
  if (lastWorkout) {
    const lwd = new Date(String(lastWorkout.date) + 'T00:00:00');
    const days_since = Math.floor((today0 - lwd) / 86400000);
    if (days_since >= 4 && days_since > interval) out.push(`🏋️ Последняя тренировка ${days_since} дн назад (${lastWorkout.day_plan}), интервал ${interval} дн — пора.`);
  }

  return { lines: out, perDay, weekKcal, weekProtein, daysWithLog, workoutsLast7: actualWorkouts, expectedWorkouts, walkRows7 };
})();

if (last7Patterns.lines.length) {
  lines.push('');
  lines.push('🚨 ПАТТЕРНЫ ПОСЛЕДНИХ 7 ДНЕЙ (используй чтобы давить на закономерности, а не молча игнорить):');
  for (const l of last7Patterns.lines) lines.push(`- ${l}`);
}

if (trainedTodayLog) {
  lines.push(`Сегодня тренировка УЖЕ выполнена и подтверждена: ${trainedTodayLog.day_plan}. Расход учтён в бюджете. НЕ говори, что сегодня отдых.`);
} else if (expected_today.type === 'rest') {
  lines.push(`Сегодня по циклу — ОТДЫХ. Следующая тренировка через ${expected_today.days_until_next} дн.`);
} else {
  lines.push(`Сегодня по циклу — Трен ${expected_today.label}.`);
  const ex = blocks[expected_today.number] || [];
  if (ex.length) {
    lines.push(`Упражнения для ${expected_today.label}:`);
    for (const e of ex) {
      const w = e.weight && e.weight !== '—' ? `, ${e.weight}` : '';
      const note = e.note ? ` (${e.note})` : '';
      lines.push(`- ${e.group}: ${e.exercise}, ${e.sets}×${e.reps}${w}${note}`);
    }
  }
}

// Полный план всех 4 блоков — для вопросов "в какой день добавить упражнение",
// "что в №3", "замени Y на Z" и т.п.
const hasAnyActiveBlock = activeNums.some(n => (blocks[n] || []).length > 0);
if (hasAnyActiveBlock) {
  lines.push('');
  lines.push(`Полный план тренировок (активных блоков: ${activeNums.length}):`);
  for (const n of activeNums) {
    if (!blocks[n] || !blocks[n].length) continue;
    lines.push(`-- ${blocksState[n].label} --`);
    for (const e of blocks[n]) {
      const w = e.weight && e.weight !== '—' ? `, ${e.weight}` : '';
      const note = e.note ? ` (${e.note})` : '';
      lines.push(`  ${e.group}: ${e.exercise}, ${e.sets}×${e.reps}${w}${note}`);
    }
  }
  if (inactiveNums.length) {
    const offLabels = inactiveNums.map(n => blocksState[n].label).join(', ');
    lines.push('');
    lines.push(`⚠️ Временно отключены (НЕ предлагать и НЕ включать в цикл): ${offLabels}. Если юзер просит «покажи план №X» из отключённых — скажи что блок временно отключён.`);
  }
}
// --- Products catalog -------------------------------------------
const productsRows = $('Read Products').all().map(i => i.json).filter(r => r && r.name);
if (productsRows.length) {
  lines.push('');
  lines.push('Справочник продуктов (используй ТОЧНЫЕ числа отсюда, не угадывай):');
  for (const p of productsRows) {
    const aliases = p.aliases ? ` [${p.aliases}]` : '';
    const ds = p.default_serving_g ? `, 1 порция = ${p.default_serving_g}г` : '';
    const notes = p.notes ? ` — ${p.notes}` : '';
