  function classify(desc, kcal, protein, carbs, fat) {
    const lc = String(desc || '').toLowerCase();
    if (kcal <= 0) return { znak: '👍', comment: 'нет данных' };
    const pPct = protein * 4 / kcal * 100;
    const cPct = carbs   * 4 / kcal * 100;
