    if (pPct < 8)  return { znak: '⚠️', comment: 'мало белка' };
    return { znak: '👍', comment: 'нормально' };
  }

  // Регулярка: <emoji> <description> — <kcal> ккал, <protein>г белка [— коммент до конца строки]
  const lineRe = /([✅👍⚠❌][️]?)\s+([^\n—]+?)\s+—\s+([\d.,]+)\s*ккал[,.]?\s*([\d.,]+)\s*г\s+белка(?:\s+—[^\n]*)?/gu;
  payload.reply = payload.reply.replace(lineRe, (m, _oldZnak, desc, kcalStr, proteinStr) => {
    const kcal = Number(String(kcalStr).replace(',', '.'));
    const protein = Number(String(proteinStr).replace(',', '.'));
    const lcDesc = String(desc).toLowerCase().trim();
