    });
    const carbs = Number(row?.carbs) || 0;
    const fat = Number(row?.fat) || 0;
    const { znak, comment } = classify(desc, kcal, protein, carbs, fat);
    return `${znak} ${desc} — ${kcalStr} ккал, ${proteinStr}г белка — ${comment}`;
  });

  // Добавим пустую строку между блюдами (после строки заканчивающейся на коммент)
