// === Telegram-safe HTML: чиним кривую разметку от модели ===
// Telegram parse_mode=HTML падает на любом неизвестном/непарном теге
// («Bad Request: can't parse entities»). Экранируем весь текст и
// возвращаем только well-formed разрешённые теги; неизвестные/непарные — выкидываем.
function telegramSafeHtml(s) {
  if (s == null) return '';
  const ALLOWED = new Set(['b','strong','i','em','u','ins','s','strike','del','code','pre','blockquote','tg-spoiler']);
  const esc = (t) => t.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const parts = String(s).split(/(<\/?[a-zA-Z][a-zA-Z0-9-]*(?:\s[^<>]*)?>)/g);
  const stack = [];
  let out = '';
  for (const part of parts) {
    const m = part.match(/^<(\/?)([a-zA-Z][a-zA-Z0-9-]*)(\s[^<>]*)?>$/);
    if (!m) { out += esc(part); continue; }            // обычный текст → экранируем
    const closing = m[1] === '/';
    const tag = m[2].toLowerCase();
    const attrs = m[3] || '';
    if (tag === 'a') {                                  // ссылка: оставляем только с валидным href
      if (closing) { if (stack[stack.length - 1] === 'a') { stack.pop(); out += '</a>'; } }
      else {
        const hm = attrs.match(/href\s*=\s*["']([^"'<>]+)["']/i);
        if (hm) { stack.push('a'); out += '<a href="' + hm[1].replace(/"/g, '') + '">'; }
      }
      continue;
    }
    if (!ALLOWED.has(tag)) continue;                    // неизвестный тег → выкидываем
    if (closing) {
      if (stack[stack.length - 1] === tag) { stack.pop(); out += '</' + tag + '>'; }  // закрываем только парный сверху
    } else { stack.push(tag); out += '<' + tag + '>'; }
  }
  while (stack.length) { out += '</' + stack.pop() + '>'; }  // дозакрыть незакрытое
  return out;
}
