const item = $input.first().json;
const d = item.data || {};
const sex = (() => { const s = String(d.sex || 'm').toLowerCase(); return (s.startsWith('f') || s.startsWith('ж')) ? 'f' : 'm'; })();
const height = Number(d.height_cm) || 0;
const weight = Number(d.weight_kg) || 0;
const age = Number(d.age) || 0;
const activity = String(d.activity_level || 'moderate').toLowerCase();
const goal = String(d.goal || 'maintain').toLowerCase();
// Фон (NEAT) от образа жизни — БЕЗ спорта; логированные ходьба/тренировки идут сверху.
const ACT_BASELINE = { sedentary:150, light:250, moderate:350, active:500, very:650 };
const baseline = ACT_BASELINE[activity] != null ? ACT_BASELINE[activity] : 350;
const goalMult = ({ lose:0.8, maintain:1.0, gain:1.15 })[goal] || 1.0;
const bmr = Math.round(sex === 'f' ? 10*weight + 6.25*height - 5*age - 161 : 10*weight + 6.25*height - 5*age + 5);
const floor = Math.round(bmr * 1.1);
const target_kcal = Math.max(floor, Math.round((bmr + baseline) * goalMult)); // базовая цель (rest day)
const target_protein_g = Math.round(weight * 1.8);
const target_fat_g = Math.round(weight * 1.0);
const target_carbs_g = Math.max(0, Math.round((target_kcal - target_protein_g*4 - target_fat_g*9) / 4));
const training_days_interval = Number(d.training_days_interval) || 1;
const daily_baseline_kcal = baseline;
const updated_at = new Date().toISOString();
return [{ json: { ...item, profile_row: {
  chat_id: item.chat_id, height_cm: height, weight_kg: weight, age, sex,
  activity_level: activity, goal, training_days_interval, bmr, daily_baseline_kcal,
  target_kcal, target_protein_g, target_fat_g, target_carbs_g, updated_at,
} } }];

const item = $input.first().json;
const data = item.data || {};
const criteria = String(data.criteria || 'last_today').toLowerCase();
const query = String(data.query || '').toLowerCase();
const targetDate = String(data.target_date || item.date);

// Items из Read Food Log в том же порядке, что строки в Sheets.
// Header в строке 1 → первая дата-строка = sheet row 2 → item index 0.
const foodRows = $('Read Food Log').all().map((it, idx) => ({
  ...it.json,
  _row: idx + 2,
}));

let target = null;
if (criteria === 'last') {
  target = foodRows[foodRows.length - 1] || null;
} else if (criteria === 'by_description') {
  const matches = foodRows.filter(r =>
    String(r.date) === targetDate &&
    String(r.description || '').toLowerCase().includes(query)
  );
  target = matches[matches.length - 1] || null;
} else { // last_today (default)
  const matches = foodRows.filter(r => String(r.date) === targetDate);
  target = matches[matches.length - 1] || null;
}

if (!target) {
  // Ничего не нашли — на следующую ноду не передаём, чтобы Sheets-удаление не сработало.
  return [];
}

return [{ json: {
  ...item,
  _row: target._row,
  _del_id: target.id,
  deleted_description: target.description,
  deleted_kcal: target.kcal,
} }];

// Парсим JSON ответа Router'а
const raw = $input.first().json;
let text = raw?.output?.[0]?.content?.[0]?.text ?? raw?.text ?? raw?.message?.content ?? '';
if (typeof text !== 'string') text = JSON.stringify(text);
text = text.trim().replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/,'').trim();
let parsed; try { parsed = JSON.parse(text); } catch(e) { parsed = { action: 'chat', action_group: 'coach' }; }
const action_group = parsed.action_group || 'coach';
const action = parsed.action || 'chat';
// Пробрасываем user_text и context в специалиста
const bc = $('Build Context').first().json;
return [{ json: { ...bc, action_group, classified_action: action } }];

const trigger = $('Telegram Trigger').first().json;
const text = String(trigger?.message?.text ?? '').trim();
if (/^\/start\b/.test(text)) return [{ json: trigger }];
return [];

const trigger = $('Telegram Trigger').first().json;
const fromId = String(trigger?.message?.from?.id ?? trigger?.message?.chat?.id ?? '');
const text = String(trigger?.message?.text ?? '').trim();
const allowed = $input.all().map(i => String(i.json.chat_id ?? '').trim()).filter(Boolean);
const hasBot = !!fromId && allowed.includes(fromId);
// нет доступа к AI и не /start → вежливый отказ
if (!hasBot && !/^\/start\b/.test(text)) return [{ json: trigger }];
return [];
